import { useState, useEffect } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const ScoreBar = ({ score }) => {
  const color = score >= 70 ? '#10b981' : score >= 40 ? '#f59e0b' : '#ef4444';
  return (
    <div className="flex items-center gap-2">
      <div style={{ background: '#0a0d1a', width: 80, height: 5, borderRadius: 3 }}>
        <div style={{ 
          background: color, 
          width: `${score}%`, 
          height: '100%', 
          borderRadius: 3, 
          boxShadow: `0 0 12px ${color}60`,
          transition: 'all 0.6s ease-out'
        }} />
      </div>
      <span style={{ color }} className="text-xs font-bold">{score}</span>
    </div>
  );
};

export default function AdminDashboard() {
  const [projects, setProjects] = useState([]);
  const [stats, setStats] = useState(null);
  const [filter, setFilter] = useState('pending');
  const [loading, setLoading] = useState(true);
  const [actionNote, setActionNote] = useState('');
  const [actionTarget, setActionTarget] = useState(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState(null);
  const [deletingId, setDeletingId] = useState(null);

  useEffect(() => {
    fetchStats();
    fetchProjects();
  }, [filter]);

  const fetchStats = () => {
    axios.get('/api/admin/stats').then(r => setStats(r.data)).catch(console.error);
  };

  const fetchProjects = () => {
    setLoading(true);
    axios.get(`/api/admin/projects?status=${filter}`)
      .then(r => setProjects(r.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  const handleDecision = async (id, decision) => {
    try {
      await axios.patch(`/api/admin/projects/${id}/${decision}`, { adminNote: actionNote });
      toast.success(`Project ${decision}d successfully`);
      setActionTarget(null);
      setActionNote('');
      fetchProjects();
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Action failed');
    }
  };

  const handleDelete = async (id) => {
    setDeletingId(id);
    try {
      await axios.delete(`/api/admin/projects/${id}`);
      setProjects(prev => prev.filter(p => p._id !== id));
      setConfirmDeleteId(null);
      toast.success('Project deleted successfully.');
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to delete project.');
    } finally {
      setDeletingId(null);
    }
  };

  const statsList = stats ? [
    { label: 'Total Projects', value: stats.totalProjects, color: '#00d4aa', icon: '📊' },
    { label: 'Pending Review', value: stats.pendingProjects, color: '#f59e0b', icon: '⏳' },
    { label: 'Approved', value: stats.approvedProjects, color: '#10b981', icon: '✓' },
    { label: 'Rejected', value: stats.rejectedProjects, color: '#ef4444', icon: '✗' },
    { label: 'Total Users', value: stats.totalUsers, color: '#8b5cf6', icon: '👥' },
    { label: 'Total Funded', value: `$${(stats.totalFunding || 0).toLocaleString()}`, color: '#06b6d4', icon: '💰' },
  ] : [];

  const NetworkBackground = () => (
    <svg style={{
      position: 'fixed',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      pointerEvents: 'none',
      zIndex: 0,
    }} viewBox="0 0 1200 800">
      <defs>
        <filter id="glow">
          <feGaussianBlur stdDeviation="3" result="coloredBlur"/>
          <feMerge>
            <feMergeNode in="coloredBlur"/>
            <feMergeNode in="SourceGraphic"/>
          </feMerge>
        </filter>
        <pattern id="grid" width="80" height="80" patternUnits="userSpaceOnUse">
          <path d="M 80 0 L 0 0 0 80" fill="none" stroke="rgba(0, 212, 170, 0.03)" strokeWidth="0.5"/>
        </pattern>
      </defs>

      {/* Grid background */}
      <rect width="1200" height="800" fill="url(#grid)" />

      {/* Animated gradient meshes */}
      <circle cx="200" cy="150" r="200" fill="rgba(0, 212, 170, 0.08)" filter="url(#glow)" opacity="0.6"/>
      <circle cx="1000" cy="600" r="250" fill="rgba(139, 92, 246, 0.06)" filter="url(#glow)" opacity="0.5"/>
      <circle cx="600" cy="400" r="180" fill="rgba(16, 185, 129, 0.04)" filter="url(#glow)" opacity="0.4"/>

      {/* Network nodes */}
      {[
        {x: 150, y: 100}, {x: 300, y: 200}, {x: 500, y: 150}, {x: 700, y: 220},
        {x: 900, y: 180}, {x: 1050, y: 300}, {x: 200, y: 450}, {x: 600, y: 500},
        {x: 950, y: 450}, {x: 400, y: 650}, {x: 800, y: 700}, {x: 100, y: 750}
      ].map((node, idx) => (
        <g key={idx}>
          <circle cx={node.x} cy={node.y} r="3" fill="rgba(0, 212, 170, 0.3)" />
          <circle cx={node.x} cy={node.y} r="6" fill="none" stroke="rgba(0, 212, 170, 0.15)" strokeWidth="1"/>
        </g>
      ))}

      {/* Connection lines */}
      <line x1="150" y1="100" x2="300" y2="200" stroke="rgba(0, 212, 170, 0.1)" strokeWidth="0.5"/>
      <line x1="300" y1="200" x2="500" y2="150" stroke="rgba(0, 212, 170, 0.1)" strokeWidth="0.5"/>
      <line x1="500" y1="150" x2="700" y2="220" stroke="rgba(0, 212, 170, 0.1)" strokeWidth="0.5"/>
      <line x1="700" y1="220" x2="900" y2="180" stroke="rgba(0, 212, 170, 0.1)" strokeWidth="0.5"/>
      <line x1="900" y1="180" x2="1050" y2="300" stroke="rgba(0, 212, 170, 0.1)" strokeWidth="0.5"/>
      <line x1="200" y1="450" x2="600" y2="500" stroke="rgba(139, 92, 246, 0.1)" strokeWidth="0.5"/>
      <line x1="600" y1="500" x2="950" y2="450" stroke="rgba(139, 92, 246, 0.1)" strokeWidth="0.5"/>
      <line x1="400" y1="650" x2="800" y2="700" stroke="rgba(0, 212, 170, 0.08)" strokeWidth="0.5"/>
    </svg>
  );

  return (
    <div style={{
      minHeight: '100vh',
      background: '#0a0d1a',
      backgroundAttachment: 'fixed',
      position: 'relative',
      overflow: 'hidden'
    }}>
      {/* Background Elements */}
      <NetworkBackground />

      {/* Dark overlay for better readability */}
      <div style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        pointerEvents: 'none',
        zIndex: 1,
        background: 'linear-gradient(135deg, rgba(10, 13, 26, 0.92) 0%, rgba(10, 13, 26, 0.88) 50%, rgba(10, 13, 26, 0.92) 100%)',
      }} />

      {/* Animated gradient orbs */}
      <div style={{
        position: 'fixed',
        top: '-10%',
        left: '-5%',
        width: '400px',
        height: '400px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(0, 212, 170, 0.15) 0%, transparent 70%)',
        pointerEvents: 'none',
        zIndex: 1,
        filter: 'blur(40px)',
        animation: 'float 20s ease-in-out infinite',
      }} />
      <div style={{
        position: 'fixed',
        bottom: '-15%',
        right: '-5%',
        width: '500px',
        height: '500px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(139, 92, 246, 0.12) 0%, transparent 70%)',
        pointerEvents: 'none',
        zIndex: 1,
        filter: 'blur(50px)',
        animation: 'float 25s ease-in-out infinite reverse',
      }} />

      <style>{`
        @keyframes slideUp {
          from {
            opacity: 0;
            transform: translateY(30px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        @keyframes slideInRight {
          from {
            opacity: 0;
            transform: translateX(30px);
          }
          to {
            opacity: 1;
            transform: translateX(0);
          }
        }

        @keyframes fadeIn {
          from {
            opacity: 0;
          }
          to {
            opacity: 1;
          }
        }

        @keyframes float {
          0%, 100% {
            transform: translateY(0px);
          }
          50% {
            transform: translateY(30px);
          }
        }

        @keyframes pulse {
          0%, 100% {
            opacity: 1;
          }
          50% {
            opacity: 0.8;
          }
        }

        @keyframes shimmer {
          0% {
            background-position: -1000px 0;
          }
          100% {
            background-position: 1000px 0;
          }
        }
      `}</style>

      <div className="px-6 py-12 relative z-10">
        <div className="max-w-7xl mx-auto">

          {/* Premium Header */}
          <div className="mb-14" style={{ animation: 'slideUp 0.6s ease-out' }}>
            <div className="flex items-center gap-2 mb-3">
              <span style={{ color: '#00d4aa', fontSize: '20px', filter: 'drop-shadow(0 0 8px rgba(0, 212, 170, 0.5))' }}>⚙</span>
              <span className="text-gray-500 text-xs uppercase tracking-widest font-semibold">Admin Control Panel</span>
            </div>
            <div className="flex items-end justify-between">
              <div>
                <h1 style={{ 
                  fontFamily: 'Syne, sans-serif',
                  background: 'linear-gradient(135deg, #ffffff 0%, #00d4aa 50%, #06b6d4 100%)',
                  backgroundClip: 'text',
                  WebkitBackgroundClip: 'text',
                  WebkitTextFillColor: 'transparent',
                  fontSize: '3rem',
                  fontWeight: 900,
                  letterSpacing: '-0.02em',
                }} className="">BackerSphere X</h1>
                <p className="text-gray-500 text-sm mt-2">Project Management & AI Review System</p>
              </div>
              <div style={{
                background: 'linear-gradient(135deg, rgba(0, 212, 170, 0.1) 0%, rgba(6, 182, 212, 0.1) 100%)',
                border: '1px solid rgba(0, 212, 170, 0.2)',
                borderRadius: '12px',
                padding: '12px 20px',
              }} className="text-right">
                <div style={{ color: '#00d4aa', fontSize: '12px', fontWeight: 600 }}>SYSTEM STATUS</div>
                <div className="text-green-400 text-sm font-semibold mt-1">● Active & Running</div>
              </div>
            </div>
          </div>

          {/* Stats Grid - Enhanced */}
          {stats && (
            <div className="grid grid-cols-6 gap-4 mb-12">
              {statsList.map((s, idx) => (
                <div 
                  key={s.label}
                  style={{
                    background: `linear-gradient(135deg, rgba(17, 24, 39, 0.9) 0%, rgba(15, 23, 42, 0.7) 100%)`,
                    border: `1.5px solid rgba(0, 212, 170, 0.12)`,
                    backdropFilter: 'blur(20px)',
                    transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
                    animation: `slideUp 0.6s ease-out ${idx * 0.08}s both`,
                  }}
                  className="p-6 rounded-2xl text-center hover:shadow-2xl group cursor-pointer"
                  onMouseEnter={(e) => {
                    e.currentTarget.style.borderColor = 'rgba(0, 212, 170, 0.4)';
                    e.currentTarget.style.boxShadow = `0 25px 50px rgba(0, 212, 170, 0.15), inset 0 0 60px rgba(0, 212, 170, 0.08)`;
                    e.currentTarget.style.transform = 'translateY(-5px)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.borderColor = 'rgba(0, 212, 170, 0.12)';
                    e.currentTarget.style.boxShadow = 'none';
                    e.currentTarget.style.transform = 'translateY(0)';
                  }}
                >
                  <div style={{ fontSize: '28px', marginBottom: '8px' }}>{s.icon}</div>
                  <div style={{ 
                    color: s.color, 
                    fontFamily: 'Syne, sans-serif', 
                    textShadow: `0 0 20px ${s.color}50`,
                    fontSize: '2rem',
                  }} className="font-black">{s.value}</div>
                  <div className="text-gray-500 text-xs mt-2.5 uppercase tracking-wider font-semibold">{s.label}</div>
                  <div style={{ height: '3px', background: `linear-gradient(90deg, ${s.color}30, transparent)`, borderRadius: '2px', marginTop: '8px' }} />
                </div>
              ))}
            </div>
          )}

          {/* Filter Tabs - Enhanced */}
          <div className="flex gap-3 mb-10 flex-wrap" style={{ animation: 'slideInRight 0.6s ease-out 0.1s both' }}>
            {['pending', 'approved', 'rejected', 'all'].map((f, idx) => (
              <button
                key={f}
                onClick={() => setFilter(f)}
                style={{
                  background: filter === f 
                    ? `linear-gradient(135deg, ${filter === f ? '#00d4aa' : 'transparent'} 0%, ${filter === f ? '#00b8a6' : 'transparent'} 100%)` 
                    : 'rgba(17, 24, 39, 0.6)',
                  color: filter === f ? '#0a0d1a' : '#9ca3af',
                  border: filter === f ? '1.5px solid rgba(0, 212, 170, 0.3)' : '1.5px solid rgba(31, 41, 55, 0.8)',
                  boxShadow: filter === f ? '0 12px 30px rgba(0, 212, 170, 0.25)' : 'none',
                  backdropFilter: 'blur(15px)',
                  transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                }}
                className="px-6 py-3 rounded-xl text-sm font-bold capitalize hover:border-teal-500/50"
              >
                {f}
              </button>
            ))}
          </div>

          {/* Projects List - Enhanced */}
          {loading ? (
            <div className="text-center text-gray-500 py-24">
              <div style={{ fontSize: '32px', marginBottom: '12px', animation: 'pulse 1.5s ease-in-out infinite' }}>⏳</div>
              <div className="text-base">Loading projects...</div>
            </div>
          ) : projects.length === 0 ? (
            <div className="text-center text-gray-500 py-24">
              <div style={{ fontSize: '48px', marginBottom: '12px' }}>📭</div>
              <div className="text-base">No {filter} projects found</div>
            </div>
          ) : (
            <div className="space-y-5">
              {projects.map((p, idx) => (
                <div
                  key={p._id}
                  style={{
                    background: `linear-gradient(135deg, rgba(17, 24, 39, 0.95) 0%, rgba(15, 23, 42, 0.8) 100%)`,
                    border: '1.5px solid rgba(31, 41, 55, 0.6)',
                    backdropFilter: 'blur(15px)',
                    transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
                    animation: `slideUp 0.6s ease-out ${idx * 0.05}s both`,
                  }}
                  className="rounded-2xl p-8 hover:border-teal-500/40 group"
                  onMouseEnter={(e) => {
                    e.currentTarget.style.boxShadow = '0 40px 80px rgba(0, 212, 170, 0.12), inset 0 0 60px rgba(0, 212, 170, 0.06)';
                    e.currentTarget.style.borderColor = 'rgba(0, 212, 170, 0.3)';
                    e.currentTarget.style.transform = 'translateY(-3px)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.boxShadow = 'none';
                    e.currentTarget.style.borderColor = 'rgba(31, 41, 55, 0.6)';
                    e.currentTarget.style.transform = 'translateY(0)';
                  }}
                >

                  <div className="flex items-start justify-between mb-6">
                    <div className="flex-1">
                      <h3 className="font-black text-xl mb-2 text-white">{p.title}</h3>
                      <div className="flex gap-4 text-xs text-gray-400">
                        <span className="flex items-center gap-1">👤 {p.innovator?.name}</span>
                        <span>•</span>
                        <span className="flex items-center gap-1">🏷️ {p.category}</span>
                        <span>•</span>
                        <span className="flex items-center gap-1">🎯 ${p.fundingGoal?.toLocaleString()}</span>
                        <span>•</span>
                        <span className="flex items-center gap-1">👥 Team: {p.teamSize}</span>
                      </div>
                    </div>

                    <div className="flex items-center gap-3 ml-6">
                      <span style={{
                        color: p.status === 'approved' ? '#10b981' : p.status === 'rejected' ? '#ef4444' : '#f59e0b',
                        background: p.status === 'approved' ? 'rgba(16, 185, 129, 0.2)' : p.status === 'rejected' ? 'rgba(239, 68, 68, 0.2)' : 'rgba(245, 158, 11, 0.2)',
                        border: `1.5px solid ${p.status === 'approved' ? 'rgba(16, 185, 129, 0.5)' : p.status === 'rejected' ? 'rgba(239, 68, 68, 0.5)' : 'rgba(245, 158, 11, 0.5)'}`,
                        boxShadow: `0 0 20px ${p.status === 'approved' ? '#10b98140' : p.status === 'rejected' ? '#ef444440' : '#f59e0b40'}`,
                        backdropFilter: 'blur(10px)',
                      }} className="px-4 py-2 rounded-full text-xs font-bold capitalize">
                        {p.status}
                      </span>

                      {/* Delete Button */}
                      {confirmDeleteId === p._id ? (
                        <div className="flex items-center gap-2">
                          <span className="text-xs text-gray-400">Confirm?</span>
                          <button
                            onClick={() => handleDelete(p._id)}
                            disabled={deletingId === p._id}
                            style={{
                              background: `linear-gradient(135deg, #ef4444 0%, #dc2626 100%)`,
                              color: 'white',
                              boxShadow: '0 10px 25px rgba(239, 68, 68, 0.4)',
                            }}
                            className="px-4 py-2 rounded-lg text-xs font-bold hover:shadow-lg disabled:opacity-60 transition-all"
                          >
                            {deletingId === p._id ? '⏳' : '✓ Yes'}
                          </button>
                          <button
                            onClick={() => setConfirmDeleteId(null)}
                            style={{ background: 'rgba(31, 41, 55, 0.9)', color: '#9ca3af', border: '1px solid rgba(75, 85, 99, 0.5)' }}
                            className="px-4 py-2 rounded-lg text-xs font-bold transition-all"
                          >
                            Cancel
                          </button>
                        </div>
                      ) : (
                        <button
                          onClick={() => setConfirmDeleteId(p._id)}
                          style={{
                            border: '1.5px solid rgba(239, 68, 68, 0.4)',
                            color: '#ef4444',
                            background: 'rgba(239, 68, 68, 0.05)',
                            transition: 'all 0.3s',
                          }}
                          className="px-4 py-2 rounded-lg text-xs font-bold hover:border-red-500 hover:bg-red-500/20"
                        >
                          🗑 Delete
                        </button>
                      )}
                    </div>
                  </div>

                  <p className="text-gray-400 text-sm mb-6 leading-relaxed">{p.description}</p>

                  {/* AI Scores - Enhanced */}
                  {p.aiEvaluation?.feasibilityScore !== null ? (
                    <div style={{
                      background: `linear-gradient(135deg, rgba(10, 13, 26, 0.95) 0%, rgba(10, 15, 30, 0.85) 100%)`,
                      border: '1.5px solid rgba(0, 212, 170, 0.3)',
                      boxShadow: '0 0 40px rgba(0, 212, 170, 0.12), inset 0 0 40px rgba(0, 212, 170, 0.05)',
                      backdropFilter: 'blur(15px)',
                    }} className="rounded-2xl p-6 mb-6">
                      <p style={{ color: '#00d4aa', textShadow: '0 0 15px rgba(0, 212, 170, 0.4)' }} className="text-xs font-black uppercase tracking-widest mb-5">
                        ✦ Gemini AI Evaluation
                      </p>
                      <div className="grid grid-cols-2 gap-5 mb-5">
                        <div>
                          <div className="text-gray-500 text-xs mb-2.5 uppercase tracking-wide font-semibold">Feasibility Score</div>
                          <ScoreBar score={p.aiEvaluation.feasibilityScore} />
                        </div>
                        <div>
                          <div className="text-gray-500 text-xs mb-2.5 uppercase tracking-wide font-semibold">Success Probability</div>
                          <ScoreBar score={p.aiEvaluation.successProbability} />
                        </div>
                      </div>
                      <p className="text-gray-400 text-xs leading-relaxed border-t border-gray-700 pt-4">{p.aiEvaluation.explanation}</p>
                    </div>
                  ) : (
                    <div style={{ color: '#f59e0b' }} className="text-sm mb-6 font-medium">⏳ AI evaluation in progress...</div>
                  )}

                  {/* Approve / Reject Actions */}
                  {p.status === 'pending' && (
                    <div>
                      {actionTarget === p._id ? (
                        <div className="flex gap-3 items-center">
                          <input
                            value={actionNote}
                            onChange={e => setActionNote(e.target.value)}
                            style={{
                              background: 'rgba(10, 13, 26, 0.95)',
                              border: '1.5px solid rgba(0, 212, 170, 0.2)',
                              color: 'white',
                              backdropFilter: 'blur(10px)',
                            }}
                            className="flex-1 px-5 py-3 rounded-xl text-sm focus:outline-none focus:border-teal-500 transition-all"
                            placeholder="Admin note (optional)..."
                          />
                          <button
                            onClick={() => handleDecision(p._id, 'approve')}
                            style={{
                              background: `linear-gradient(135deg, #10b981 0%, #059669 100%)`,
                              color: 'white',
                              boxShadow: '0 10px 30px rgba(16, 185, 129, 0.4)',
                            }}
                            className="px-6 py-3 rounded-xl text-sm font-bold hover:shadow-lg transition-all"
                          >
                            ✓ Approve
                          </button>
                          <button
                            onClick={() => handleDecision(p._id, 'reject')}
                            style={{
                              background: `linear-gradient(135deg, #ef4444 0%, #dc2626 100%)`,
                              color: 'white',
                              boxShadow: '0 10px 30px rgba(239, 68, 68, 0.4)',
                            }}
                            className="px-6 py-3 rounded-xl text-sm font-bold hover:shadow-lg transition-all"
                          >
                            ✗ Reject
                          </button>
                          <button
                            onClick={() => { setActionTarget(null); setActionNote(''); }}
                            className="text-gray-400 text-sm font-medium hover:text-gray-300 transition-all"
                          >
                            Cancel
                          </button>
                        </div>
                      ) : (
                        <button
                          onClick={() => setActionTarget(p._id)}
                          style={{
                            border: '1.5px solid rgba(0, 212, 170, 0.3)',
                            color: '#9ca3af',
                            background: 'rgba(0, 212, 170, 0.08)',
                            backdropFilter: 'blur(10px)',
                            transition: 'all 0.3s',
                          }}
                          className="px-6 py-3 rounded-xl text-sm font-bold hover:border-teal-500 hover:text-white hover:bg-teal-500/20"
                        >
                          🔍 Review & Decide
                        </button>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
